32	
33	YOSYS_NAMESPACE_BEGIN
34	
35	#define MAX_REG_COUNT 1000
36	
37	bool echo_mode = false;
38	Pass *first_queued_pass;
39	Pass *current_pass;
40	
41	std::map<std::string, Frontend*> frontend_register;
42	std::map<std::string, Pass*> pass_register;
43	std::map<std::string, Backend*> backend_register;
44	
45	std::vector<std::string> Frontend::next_args;
46	
47	bool GarbageCollectionGuard::is_enabled_ = true;
48	
49	static bool garbage_collection_requested = false;
50	
51	void request_garbage_collection()
52	{
53		garbage_collection_requested = true;
54	}
55	
56	void try_collect_garbage()
57	{
58		if (!GarbageCollectionGuard::is_enabled() || !garbage_collection_requested)
59			return;
60		garbage_collection_requested = false;
61		RTLIL::OwningIdString::collect_garbage();
62	}
63	
64	Pass::Pass(std::string name, std::string short_help, source_location location) :
65		pass_name(name), short_help(short_help), location(location)
66	{
67		next_queued_pass = first_queued_pass;
68		first_queued_pass = this;
69		call_counter = 0;
70		runtime_ns = 0;
71	}
72	
73	void Pass::run_register()
74	{
75		if (pass_register.count(pass_name) && !replace_existing_pass())
76			log_error("Unable to register pass '%s', pass already exists!\n", pass_name);
77		pass_register[pass_name] = this;
78	}
79	
80	void Pass::init_register()
81	{
82		vector<Pass*> added_passes;
83		while (first_queued_pass) {
84			added_passes.push_back(first_queued_pass);
85			first_queued_pass->run_register();
86			first_queued_pass = first_queued_pass->next_queued_pass;
87		}
88		for (auto added_pass : added_passes)
89			added_pass->on_register();
90	}
91	
92	void Pass::done_register()
93	{
94		for (auto &it : pass_register)
95			it.second->on_shutdown();
96	
97		frontend_register.clear();
98		pass_register.clear();
99		backend_register.clear();
100		log_assert(first_queued_pass == NULL);
101	}
102	
103	void Pass::on_register()
104	{
105	}
106	
107	void Pass::on_shutdown()
108	{
109	}
110	
111	Pass::~Pass()
112	{
113	}
114	
115	Pass::pre_post_exec_state_t Pass::pre_execute()
116	{
117		pre_post_exec_state_t state;
118		call_counter++;
119		state.begin_ns = PerformanceTimer::query();
120		state.parent_pass = current_pass;
121		current_pass = this;
122		clear_flags();
123		return state;
124	}
125	
126	void Pass::post_execute(Pass::pre_post_exec_state_t state)
127	{
128		IdString::checkpoint();
129		log_suppressed();
130	
131		int64_t time_ns = PerformanceTimer::query() - state.begin_ns;
132		runtime_ns += time_ns;
133		current_pass = state.parent_pass;
134		subtract_from_current_runtime_ns(time_ns);
135	}
136	
137	void Pass::subtract_from_current_runtime_ns(int64_t time_ns)
138	{
139		if (current_pass)
140			current_pass->runtime_ns -= time_ns;
141	}
142	
143	void Pass::help()
144	{
145		auto prettyHelp = PrettyHelp();
146		if (formatted_help()) {
147			prettyHelp.log_help();
148		} else {
149			log("\n");
150			log("No help message for command `%s'.\n", pass_name);
151			log("\n");
152		}
153	}
154	
155	bool Pass::formatted_help()
156	{
157		return false;
158	}
159	
160	void Pass::clear_flags()
161	{
162	}
163	
164	void Pass::cmd_log_args(const std::vector<std::string> &args)
165	{
166		if (args.size() <= 1)
167			return;
168		log("Full command line:");
169		for (size_t i = 0; i < args.size(); i++)
170			log(" %s", args[i]);
171		log("\n");
172	}
173	
174	void Pass::cmd_error(const std::vector<std::string> &args, size_t argidx, std::string msg)
175	{
176		std::string command_text;
177		int error_pos = 0;
178	
179		for (size_t i = 0; i < args.size(); i++) {
180			if (i < argidx)
181				error_pos += args[i].size() + 1;
182			command_text = command_text + (command_text.empty() ? "" : " ") + args[i];
183		}
184	
185		log("\nSyntax error in command `%s':\n", command_text);
186		help();
187	
188		log_cmd_error("Command syntax error: %s\n> %s\n> %*s^\n",
189				msg.c_str(), command_text.c_str(), error_pos, "");
190	}
191	
192	void Pass::extra_args(std::vector<std::string> args, size_t argidx, RTLIL::Design *design, bool select)
193	{
194		for (; argidx < args.size(); argidx++)
195		{
196			std::string arg = args[argidx];
197	
198			if (arg.compare(0, 1, "-") == 0)
199				cmd_error(args, argidx, "Unknown option or option in arguments.");
200	
201			if (!select)
202				cmd_error(args, argidx, "Extra argument.");
203	
204			handle_extra_select_args(this, args, argidx, args.size(), design);
205			break;
206		}
207		// cmd_log_args(args);
208	}
209	
210	void Pass::call(RTLIL::Design *design, std::string command)
211	{
212		std::vector<std::string> args;
213	
214		std::string cmd_buf = command;
215		std::string tok = next_token(cmd_buf, " \t\r\n", true);
216	
217		if (tok.empty())
218			return;
219	
220		if (tok[0] == '!') {
221	#if defined(YOSYS_ENABLE_SPAWN)
222			cmd_buf = command.substr(command.find('!') + 1);
223			while (!cmd_buf.empty() && (cmd_buf.back() == ' ' || cmd_buf.back() == '\t' ||
224					cmd_buf.back() == '\r' || cmd_buf.back() == '\n'))
225				cmd_buf.resize(cmd_buf.size()-1);
226			log_header(design, "Shell command: %s\n", cmd_buf);
227			int retCode = run_command(cmd_buf);
228			if (retCode != 0)
229				log_cmd_error("Shell command returned error code %d.\n", retCode);
230			return;
231	#else
232			log_cmd_error("Shell is not available.\n");
233	#endif
234		}
235	
236		while (!tok.empty()) {
237			if (tok[0] == '#') {
238				int stop;
239				for (stop = 0; stop < GetSize(cmd_buf); stop++)
240					if (cmd_buf[stop] == '\r' || cmd_buf[stop] == '\n')
241						break;
242				cmd_buf = cmd_buf.substr(stop);
243			} else
244			if (tok.back() == ';') {
245				int num_semikolon = 0;
246				while (!tok.empty() && tok.back() == ';')
247					tok.resize(tok.size()-1), num_semikolon++;
248				if (!tok.empty())
249					args.push_back(tok);
250				call(design, args);
251				args.clear();
252				if (num_semikolon == 2)
253					call(design, "clean");
254				if (num_semikolon == 3)
255					call(design, "clean -purge");
256			} else
257				args.push_back(tok);
258			bool found_nl = false;
259			for (auto c : cmd_buf) {
260				if (c == ' ' || c == '\t')
261					continue;
262				if (c == '\r' || c == '\n')
263					found_nl = true;
264				break;
265			}
266			if (found_nl) {
267				call(design, args);
268				args.clear();
269			}
270			tok = next_token(cmd_buf, " \t\r\n", true);
271		}
272	
273		call(design, args);
274	}
