602	void Backend::extra_args(std::ostream *&f, std::string &filename, std::vector<std::string> args, size_t argidx, bool bin_output)
603	{
604		bool called_with_fp = f != NULL;
605	
606		for (; argidx < args.size(); argidx++)
607		{
608			std::string arg = args[argidx];
609	
610			if (arg.compare(0, 1, "-") == 0 && arg != "-")
611				cmd_error(args, argidx, "Unknown option or option in arguments.");
612			if (f != NULL)
613				cmd_error(args, argidx, "Extra filename argument in direct file mode.");
614	
615			if (arg == "-") {
616				filename = "<stdout>";
617				f = &std::cout;
618				continue;
619			}
620	
621			filename = arg;
622			rewrite_filename(filename);
623			if (filename.size() > 3 && filename.compare(filename.size()-3, std::string::npos, ".gz") == 0) {
624	#ifdef YOSYS_ENABLE_ZLIB
625				gzip_ostream *gf = new gzip_ostream;
626				if (!gf->open(filename)) {
627					delete gf;
628					log_cmd_error("Can't open output file `%s' for writing: %s\n", filename, strerror(errno));
629				}
630				yosys_output_files.insert(filename);
631				f = gf;
632	#else
633				log_cmd_error("Yosys is compiled without zlib support, unable to write gzip output.\n");
634	#endif
635			} else {
636				std::ofstream *ff = new std::ofstream;
637				ff->open(filename.c_str(), bin_output ? (std::ofstream::trunc | std::ofstream::binary) : std::ofstream::trunc);
638				yosys_output_files.insert(filename);
639				if (ff->fail()) {
640					delete ff;
641					log_cmd_error("Can't open output file `%s' for writing: %s\n", filename, strerror(errno));
642				}
643				f = ff;
644			}
645		}
646	
647		if (called_with_fp)
648			args.push_back(filename);
649		args[0] = pass_name;
650		// cmd_log_args(args);
651	
652		if (f == NULL) {
653			filename = "<stdout>";
654			f = &std::cout;
655		}
656	}
