767		bool dump_cmds_json(PrettyJson &json) {
768			// init json
769			json.begin_object();
770			json.entry("version", "Yosys command reference");
771			json.entry("generator", yosys_version_str);
772	
773			bool raise_error = false;
774			std::map<string, vector<string>> groups;
775	
776			// get root path
777			auto this_path = std::filesystem::path(source_location::current().file_name());
778			auto source_root = this_path.parent_path().parent_path();
779	
780			json.name("cmds"); json.begin_object();
781			// iterate over commands
782			for (auto &it : pass_register) {
783				auto name = it.first;
784				auto pass = it.second;
785				auto title = pass->short_help;
786	
787				auto cmd_help = PrettyHelp();
788				auto has_pretty_help = pass->formatted_help();
789	
790				if (!has_pretty_help) {
791					enum PassUsageState {
792						PUState_none,
793						PUState_signature,
794						PUState_options,
795						PUState_optionbody,
796					};
797	
798					source_location null_source;
799					string current_buffer = "";
800					auto root_listing = cmd_help.get_root();
801					auto current_listing = root_listing;
802	
803					// dump command help
804					std::ostringstream buf;
805					log_streams.push_back(&buf);
806					pass->help();
807					log_streams.pop_back();
808					std::stringstream ss;
809					ss << buf.str();
810	
811					// parse command help
812					size_t def_strip_count = 0;
813					auto current_state = PUState_none;
814					auto catch_verific = false;
815					auto blank_lines = 2;
816					for (string line; std::getline(ss, line, '\n');) {
817						// find position of first non space character
818						std::size_t first_pos = line.find_first_not_of(" \t");
819						std::size_t last_pos = line.find_last_not_of(" \t");
820						if (first_pos == std::string::npos) {
821							switch (current_state)
822							{
823							case PUState_signature:
824								root_listing->usage(current_buffer, null_source);
825								current_listing = root_listing;
826								current_state = PUState_none;
827								current_buffer = "";
828								break;
829							case PUState_none:
830							case PUState_optionbody:
831								blank_lines += 1;
832								break;
833							default:
834								break;
835							}
836							// skip empty lines
837							continue;
838						}
839	
840						// strip leading and trailing whitespace
841						std::string stripped_line = line.substr(first_pos, last_pos - first_pos +1);
842						bool IsDefinition = stripped_line[0] == '-';
843						IsDefinition &= stripped_line[1] != ' ' && stripped_line[1] != '>';
844						bool IsDedent = def_strip_count && first_pos < def_strip_count;
845						bool IsIndent = def_strip_count < first_pos;
846	
847						// line looks like a signature
848						bool IsSignature = stripped_line.find(name) == 0 && (stripped_line.length() == name.length() || stripped_line.at(name.size()) == ' ');
849	
850						if (IsSignature && first_pos <= 4 && (blank_lines >= 2 || current_state == PUState_signature)) {
851							if (current_state == PUState_options || current_state == PUState_optionbody) {
852								current_listing->codeblock(current_buffer, "none", null_source);
853								current_buffer = "";
854							} else if (current_state == PUState_signature) {
855								root_listing->usage(current_buffer, null_source);
856								current_buffer = "";
857							} else if (current_state == PUState_none && !current_buffer.empty()) {
858								current_listing->codeblock(current_buffer, "none", null_source);
859								current_buffer = "";
860							}
861							current_listing = root_listing;
862							current_state = PUState_signature;
863							def_strip_count = first_pos;
864							catch_verific = false;
865						} else if (IsDedent) {
866							def_strip_count = first_pos;
867							if (current_state == PUState_optionbody) {
868								if (!current_buffer.empty()) {
869									current_listing->codeblock(current_buffer, "none", null_source);
870									current_buffer = "";
871								}
872								if (IsIndent) {
873									current_state = PUState_options;
874									current_listing = root_listing->back();
875								} else {
876									current_state = PUState_none;
877									current_listing = root_listing;
878								}
879							} else {
880								current_state = PUState_none;
881							}
882						}
883	
884						if (IsDefinition && !catch_verific && current_state != PUState_signature) {
885							if (!current_buffer.empty()) {
886								current_listing->codeblock(current_buffer, "none", null_source);
887								current_buffer = "";
888							}
889							current_state = PUState_options;
890							current_listing = root_listing->open_option(stripped_line, null_source);
891							def_strip_count = first_pos;
892						} else {
893							if (current_state == PUState_options) {
894								current_state = PUState_optionbody;
895							}
896							if (current_buffer.empty())
897								current_buffer = stripped_line;
898							else if (current_state == PUState_signature && IsIndent)
899								current_buffer += stripped_line;
900							else if (current_state == PUState_none) {
901								current_buffer += (blank_lines > 0 ? "\n\n" : "\n") + line;
902							} else
903								current_buffer += (blank_lines > 0 ? "\n\n" : "\n") + stripped_line;
904							if (stripped_line.compare("Command file parser supports following commands in file:") == 0)
905								catch_verific = true;
906						}
907						blank_lines = 0;
908					}
909	
910					if (!current_buffer.empty()) {
911						if (current_buffer.size() > 64 && current_buffer.substr(0, 64).compare("The following commands are executed by this synthesis command:\n\n") == 0) {
912							current_listing->paragraph(current_buffer.substr(0, 62), null_source);
913							current_listing->codeblock(current_buffer.substr(64), "yoscrypt", null_source);
914						} else
915							current_listing->codeblock(current_buffer, "none", null_source);
916						current_buffer = "";
917					}
918				}
919	
920				// fix path
921				string source_file = pass->location.file_name();
922				bool has_source = source_file.compare("unknown") != 0;
923				std::filesystem::path source_path;
924				auto skip_source_group = false;
925	
926				if (has_source) {
927					source_path = fixup_source_path(pass->location.file_name(), source_root, &skip_source_group);
928					source_file = source_path.string();
929				}
930	
931				// attempt auto group
932				if (!cmd_help.has_group()) {
933					if (pass->internal_flag)
934						cmd_help.group = "internal";
935					else if (source_file.find("backends/") == 0 || (!has_source && name.find("read_") == 0))
936						cmd_help.group = "backends";
937					else if (source_file.find("frontends/") == 0 || (!has_source && name.find("write_") == 0))
938						cmd_help.group = "frontends";
939					else if (has_source) {
940						if (source_path.has_parent_path() && !skip_source_group)
941							cmd_help.group = source_path.parent_path().string();
942					}
943					// implicit !has_source
944					else if (name.find("equiv") == 0)
945						cmd_help.group = "passes/equiv";
946					else if (name.find("fsm") == 0)
947						cmd_help.group = "passes/fsm";
948					else if (name.find("memory") == 0)
949						cmd_help.group = "passes/memory";
950					else if (name.find("opt") == 0)
951						cmd_help.group = "passes/opt";
952					else if (name.find("proc") == 0)
953						cmd_help.group = "passes/proc";
954				}
955	
956				if (groups.count(cmd_help.group) == 0) {
957					groups[cmd_help.group] = vector<string>();
958				}
959				groups[cmd_help.group].push_back(name);
960	
961				// write to json
962				json.name(name.c_str()); json.begin_object();
963				json.entry("title", title);
964				json.name("content"); json.begin_array();
965				for (auto &content : cmd_help)
966					json.value(content.to_json(source_root));
967				json.end_array();
968				json.entry("group", cmd_help.group);
969				json.entry("source_file", source_file);
970				json.entry("source_line", pass->location.line());
971				json.entry("source_func", pass->location.function_name());
972				json.entry("experimental_flag", pass->experimental_flag);
973				json.entry("internal_flag", pass->internal_flag);
974				json.end_object();
975			}
976			json.end_object();
977	
978			json.entry("groups", groups);
979	
980			json.end_object();
981			return raise_error;
982		}
983		bool dump_cells_json(PrettyJson &json) {
984			// init json
985			json.begin_object();
986			json.entry("version", "Yosys internal cells");
987			json.entry("generator", yosys_maybe_version());
988	
989			dict<string, vector<string>> groups;
990			dict<string, pair<SimHelper, StaticCellTypes::CellTableBuilder::CellInfo>> cells;
991	
992			// iterate over cells
993			bool raise_error = false;
994			for (auto it : StaticCellTypes::builder.cells) {
995				if (!StaticCellTypes::categories.is_known(it.type))
996					continue;
997				auto name = it.type.str();
998				if (cell_help_messages.contains(name)) {
999					auto cell_help = cell_help_messages.get(name);
1000					groups[cell_help.group].emplace_back(name);
1001					auto cell_pair = pair<SimHelper, StaticCellTypes::CellTableBuilder::CellInfo>(cell_help, it);
1002					cells.emplace(name, cell_pair);
1003				} else {
1004					log("ERROR: Missing cell help for cell '%s'.\n", name);
1005					raise_error |= true;
1006				}
1007			}
1008			for (auto &it : cell_help_messages.cell_help) {
1009				if (cells.count(it.first) == 0) {
1010					log_warning("Found cell model '%s' without matching cell type.\n", it.first);
1011				}
1012			}
1013	
1014			// write to json
1015			json.name("groups"); json.begin_object();
1016			groups.sort();
1017			for (auto &it : groups) {
1018				json.name(it.first.c_str()); json.value(it.second);
1019			}
1020			json.end_object();
1021	
1022			json.name("cells"); json.begin_object();
1023			cells.sort();
1024			for (auto &it : cells) {
1025				auto ch = it.second.first;
1026				auto ct = it.second.second;
1027				json.name(ch.name.c_str()); json.begin_object();
1028				json.name("title"); json.value(ch.title);
1029				json.name("ports"); json.value(ch.ports);
1030				json.name("source"); json.value(ch.source);
1031				json.name("desc"); json.value(ch.desc);
1032				json.name("code"); json.value(ch.code);
1033				vector<string> inputs, outputs;
1034				for (auto &input : ct.inputs)
1035					inputs.push_back(input.str());
1036				json.name("inputs"); json.value(inputs);
1037				for (auto &output : ct.outputs)
1038					outputs.push_back(output.str());
1039				json.name("outputs"); json.value(outputs);
1040				vector<string> properties;
1041				// CellType properties
1042				if (ct.features.is_evaluable) properties.push_back("is_evaluable");
1043				if (ct.features.is_combinatorial) properties.push_back("is_combinatorial");
1044				if (ct.features.is_synthesizable) properties.push_back("is_synthesizable");
1045				// SimHelper properties
1046				size_t last = 0; size_t next = 0;
1047				while ((next = ch.tags.find(", ", last)) != string::npos) {
1048					properties.push_back(ch.tags.substr(last, next-last));
1049					last = next + 2;
1050				}
1051				auto final_tag = ch.tags.substr(last);
1052				if (final_tag.size()) properties.push_back(final_tag);
1053				json.name("properties"); json.value(properties);
1054				json.end_object();
1055			}
1056			json.end_object();
1057	
1058			json.end_object();
1059			return raise_error;
1060		}
